parameters.jsCode:
const pedido = $input.all()[0].json.body;

// Formateamos la lista de artículos
let listaArticulos = "";
if (pedido.lista_articulos && Array.isArray(pedido.lista_articulos)) {
  pedido.lista_articulos.forEach(item => {
    listaArticulos += `▪️ ${item.cantidad}x ${item.producto} (${item.tamano})\n`;
    if (item.orilla_extra && item.orilla_extra !== 'Normal') {
        listaArticulos += `   ${item.orilla_extra}\n`;
    }
  });
}

// Generamos el link de Google Maps si hay coordenadas
let linkMapa = "No proporcionada";
if (pedido.coordenadas) {
  linkMapa = `https://maps.google.com/?q=${pedido.coordenadas.replace(' ', '')}`;
}

// Armamos el "Ticket" final de WhatsApp
const mensajeTicket = `
🚨 *¡NUEVO PEDIDO CAPRICCIO!* 🚨
#Orden: ${Math.floor(Math.random() * 10000)}

👤 *Cliente:* ${pedido.cliente_nombre}
📞 *Tel:* ${pedido.cliente_telefono}
💳 *Pago:* ${pedido.metodo_pago}

🛒 *DETALLE DEL PEDIDO:*
${listaArticulos}
💰 *TOTAL A COBRAR: $${pedido.total_pagar}*

🛵 *DATOS DE ENTREGA:*
📍 *Dirección:* ${pedido.direccion_entrega}
🗺️ *Google Maps:* ${linkMapa}
`;

return [
  {
    json: {
      mensaje_formateado: mensajeTicket,
      telefono_destino: "52" + pedido.cliente_telefono,
      nombre_cliente: pedido.cliente_nombre
    }
  }
];

